namespace sttSav
{
  BinaryValue BinaryValue::operator [] (uint32_t index) const
                                                     {
		STTSAV_ASSERT(IsValid());
		STTSAV_ASSERT(IsArray());
		STTSAV_ASSERT(index < Size());

		uint64_t off = childOffset();

		for (uint32_t i = 0; i < index; ++i) {
			BinaryValue v;
			v.dec = dec;
			v.offset = off;
			off = v.nextOffset();
			}

		BinaryValue out;
		out.dec = dec;
		out.offset = off;
		return out;
		}
}
namespace sttSav
{
  BinaryValue BinaryValue::operator [] (char const * key) const
                                                       {
		STTSAV_ASSERT(IsValid());
		STTSAV_ASSERT(IsObject());
		
		uint64_t off = childOffset();
		for (uint32_t i = 0; i < Size(); ++i) {
			StringDecoder d(*dec);
			d.seek = off;
			
			STTSAV_STRING name;
			d.parseString(name);

			if (name == key) {
				BinaryValue out;
				out.dec = dec;
				out.offset = d.seek;
				return out;
				}
			
			BinaryValue v;
			v.dec = dec;
			v.offset = d.seek;
			off = v.nextOffset();
			}
		return BinaryValue();
		}
}
